insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'P is the mother of Q. Q is the brother of R. How is P related to R?', 'P, Q की mother है। Q, R का brother है। P, R से कैसे related है?', 'Q and R are siblings; P is Q''s mother, so P is R''s mother. Trace one link at a time and answer from the asked person''s viewpoint. Therefore, answer = Mother.', 'Blood relation questions are solved by drawing a small family chain. Keep gender and direction fixed; most wrong answers reverse the viewpoint. Final answer is Mother.', 'Q and R are siblings; P is Q''s mother, so P is R''s mother. एक-एक link trace करें और asked person के viewpoint से relation दें। अतः answer = Mother।', 'Blood relation questions में छोटा family chain बनता है। Gender और direction fix रखें; ज़्यादातर errors viewpoint reverse करने से होते हैं। Final answer Mother है।', 'EASY', array['blood-relations','family-tree']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
