insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 2, 'M is the son of N. N is the sister of O. How is O related to M?', 'M, N का son है। N, O की sister है। O, M से कैसे related है?', 'O is sibling of M''s mother N, so O is uncle/aunt. Trace one link at a time and answer from the asked person''s viewpoint. Therefore, answer = Uncle/Aunt.', 'Blood relation questions are solved by drawing a small family chain. Keep gender and direction fixed; most wrong answers reverse the viewpoint. Final answer is Uncle/Aunt.', 'O is sibling of M''s mother N, so O is uncle/aunt. एक-एक link trace करें और asked person के viewpoint से relation दें। अतः answer = Uncle/Aunt।', 'Blood relation questions में छोटा family chain बनता है। Gender और direction fix रखें; ज़्यादातर errors viewpoint reverse करने से होते हैं। Final answer Uncle/Aunt है।', 'EASY', array['blood-relations','family-tree']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
